import{c as e,Q as d,j as a,m as o}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"URL 大小写敏感规则","description":"","frontmatter":{},"headers":[],"relativePath":"杂项/URL大小写敏感规则.md","filePath":"杂项/URL大小写敏感规则.md","lastUpdated":1782819443000}'),n={name:"杂项/URL大小写敏感规则.md"};function r(s,t,c,l,i,p){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="url-大小写敏感规则" tabindex="-1">URL 大小写敏感规则 <a class="header-anchor" href="#url-大小写敏感规则" aria-label="Permalink to &quot;URL 大小写敏感规则&quot;">​</a></h1><blockquote><p>一份「随时回看」的速查:URL 不是整体统一一套规则,而是<strong>逐段</strong>各有各的脾气。 核心心智:<strong>域名以左不区分,路径以右大多区分——分界点在第一个 <code>/</code>。</strong></p></blockquote><hr><h2 id="一、一张图看清分界" tabindex="-1">一、一张图看清分界 <a class="header-anchor" href="#一、一张图看清分界" aria-label="Permalink to &quot;一、一张图看清分界&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> https :// Example.COM : 443 / Path/To/Page ? Name=Tom # Section</span></span>
<span class="line"><span> └─┬─┘    └────┬─────┘ └┬┘ └─────┬───────┘ └───┬────┘ └──┬───┘</span></span>
<span class="line"><span> scheme      host     port    path          query     fragment</span></span>
<span class="line"><span>不区分      不区分    —      区分           区分        区分</span></span>
<span class="line"><span>└──────── 不区分大小写 ────────┘└──────────── 区分大小写 ────────────┘</span></span>
<span class="line"><span>                              ↑</span></span>
<span class="line"><span>                        分界:第一个 &quot;/&quot;</span></span></code></pre></div><p><strong>记忆口诀:<code>://</code> 到第一个 <code>/</code> 之间(协议+域名)不区分;之后(路径+参数+锚点)都区分。</strong></p><hr><h2 id="二、逐段规则" tabindex="-1">二、逐段规则 <a class="header-anchor" href="#二、逐段规则" aria-label="Permalink to &quot;二、逐段规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部分</th><th>示例</th><th style="text-align:center;">区分大小写</th><th>原因</th></tr></thead><tbody><tr><td>scheme 协议</td><td><code>HTTP://</code> = <code>http://</code></td><td style="text-align:center;">❌ 不区分</td><td>RFC 3986 规定按小写归一</td></tr><tr><td>host 域名</td><td><code>Example.COM</code> = <code>example.com</code></td><td style="text-align:center;">❌ 不区分</td><td>DNS 解析不区分大小写</td></tr><tr><td>port 端口</td><td><code>:443</code></td><td style="text-align:center;">—</td><td>纯数字,无大小写</td></tr><tr><td>path 路径</td><td><code>/Page</code> ≠ <code>/page</code></td><td style="text-align:center;">✅ 区分</td><td>由服务器/文件系统决定</td></tr><tr><td>query 查询串</td><td><code>?Name=Tom</code> ≠ <code>?name=tom</code></td><td style="text-align:center;">✅ 区分</td><td>参数名与值都由后端代码解析</td></tr><tr><td>fragment 锚点</td><td><code>#Top</code> ≠ <code>#top</code></td><td style="text-align:center;">✅ 区分</td><td>由前端/浏览器按字符匹配</td></tr><tr><td>userinfo 用户名密码</td><td>—</td><td style="text-align:center;">✅ 区分</td><td>—</td></tr><tr><td>百分号编码</td><td><code>%2F</code> = <code>%2f</code></td><td style="text-align:center;">❌ 不区分</td><td>十六进制位不区分大小写</td></tr></tbody></table><hr><h2 id="三、实际会踩的坑" tabindex="-1">三、实际会踩的坑 <a class="header-anchor" href="#三、实际会踩的坑" aria-label="Permalink to &quot;三、实际会踩的坑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>表现</th></tr></thead><tbody><tr><td>Linux 服务器</td><td>文件系统<strong>大小写敏感</strong>,<code>/Img/a.png</code> 与 <code>/img/a.png</code> 是两个文件</td></tr><tr><td>Windows / macOS 服务器</td><td>文件系统默认<strong>不敏感</strong>,本地测试「看起来不区分」,上线 Linux 就 404</td></tr><tr><td>后端路由框架</td><td>Spring / Express / Nginx <code>location</code> 默认区分,可配置忽略</td></tr><tr><td>CDN / 缓存</td><td>按 URL 当 key,大小写不同 → 命中两条独立缓存,浪费 + 不一致</td></tr><tr><td>短链 / 二维码</td><td>用户手输、OCR、口头传播极易大小写错乱 → 打不开</td></tr></tbody></table><hr><h2 id="四、实践建议" tabindex="-1">四、实践建议 <a class="header-anchor" href="#四、实践建议" aria-label="Permalink to &quot;四、实践建议&quot;">​</a></h2><ol><li><strong>路径一律小写</strong>:统一用 <code>kebab-case</code>(短横线),不用驼峰,杜绝大小写歧义。</li><li><strong>生成型 URL(短链 / 到店码 / 分享链接)只用小写</strong>,必要时只用大小写不混淆的字符集(去掉 <code>O/0</code>、<code>l/1</code>、<code>I</code> 等)。</li><li><strong>服务端做大小写归一</strong>:对域名、协议强制小写;路径若想容错,统一在网关层 301 重定向到小写版本,而不是两份都返回 200(避免重复内容、缓存分裂)。</li><li><strong>查询参数名约定固定大小写</strong>,前后端对齐一套命名规范,别依赖框架的「容错」。</li></ol><hr><blockquote><p>一句话总结:<strong>域名随便大小写都行,<code>/</code> 之后的部分请当作严格区分——能小写就全小写。</strong></p></blockquote>`,17)])])}const m=e(n,[["render",r]]);export{g as __pageData,m as default};
